Real64 Ra(Real64 const Ts, Real64 const Ta)
    {
        constexpr Real64 sigma = 5.67e-8; // W/m^2/K^4 , Stefan-Boltzmann constant
        constexpr Real64 epsilon = 0.97;  //           , emissivity of surface, steadman1979
        constexpr Real64 hc = 17.4;
        constexpr Real64 phi_rad = 0.85;
        Real64 const hr = epsilon * phi_rad * sigma * (std::pow(Ts, 2) + std::pow(Ta, 2)) * (Ts + Ta);
        return 1.0 / (hc + hr);
    }

Real64 Ra_bar(Real64 const Tf, Real64 const Ta)
    {
        constexpr Real64 sigma = 5.67e-8; // W/m^2/K^4 , Stefan-Boltzmann constant
        constexpr Real64 epsilon = 0.97;  //           , emissivity of surface, steadman1979
        constexpr Real64 hc = 11.6;
        constexpr Real64 phi_rad = 0.79;
        Real64 const hr = epsilon * phi_rad * sigma * (std::pow(Tf, 2) + std::pow(Ta, 2)) * (Tf + Ta);
        return 1.0 / (hc + hr);
    }

Real64 Ra_un(Real64 const Ts, Real64 const Ta)
    {
        constexpr Real64 sigma = 5.67e-8; // W/m^2/K^4 , Stefan-Boltzmann constant
        constexpr Real64 epsilon = 0.97;  //           , emissivity of surface, steadman1979
        constexpr Real64 hc = 12.3;
        constexpr Real64 phi_rad = 0.80;
        Real64 const hr = epsilon * phi_rad * sigma * (std::pow(Ts, 2) + std::pow(Ta, 2)) * (Ts + Ta);
        return 1.0 / (hc + hr);
    }

Real64 SafeDivide(Real64 const a, Real64 const b)
{

    // returns a / b while preventing division by zero

    // Locals
    Real64 constexpr SMALL(1.E-10);

    if (std::abs(b) >= SMALL) {
        return a / b;
    }
    return a / sign(SMALL, b);
}

Real64 rotAzmDiffDeg(Real64 AzmA, Real64 AzmB)
{
    // This function takes two (azimuth) angles in Degree(s),
    // and returns the rotational angle difference in Degree(s).

    Real64 diff = AzmB - AzmA;
    if (diff > 180.0) {
        diff = 360.0 - diff;
    } else if (diff < -180.0) {
        diff = 360.0 + diff;
    }
    return std::abs(diff);
}

Real64 WVDC(Real64 const Temperature, Real64 const ambp)
    {
        // FUNCTION INFORMATION:
        //       AUTHOR         Phillip Biddulph
        //       DATE WRITTEN   June 2008
        //       MODIFIED       na
        //       RE-ENGINEERED  na

        // PURPOSE OF THIS FUNCTION:
        // To calculate the Water Vapor Diffusion Coefficient in air
        // using the temperature and ambient atmospheric pressor

        // REFERENCES:
        // K?zel, H.M. (1995) Simultaneous Heat and Moisture Transport in Building Components.
        // One- and two-dimensional calculation using simple parameters. IRB Verlag 1995

        // Return value
        Real64 WVDC;

        WVDC = (2.e-7 * std::pow(Temperature + Constant::Kelvin, 0.81)) / ambp;

        return WVDC;
    }

Real64 SafeDiv(Real64 const a, Real64 const b)
    {

        // SUBROUTINE INFORMATION:
        //       AUTHOR         Michael Wetter
        //       DATE WRITTEN   March 1999
        //       MODIFIED       na
        //       RE-ENGINEERED  na

        // PURPOSE OF THIS FUNCTION:
        // Returns a / b while preventing division by zero

        // METHODOLOGY EMPLOYED:
        // Check for small or zero values before performing division

        if (std::abs(b) < SMALL) {
            return a / sign(SMALL, b);
        }
        return a / b;
    }

Real64 TempSItoIP(Real64 const Temp)
    {
        return (Temp * 9.0 / 5.0) + 32.0;
    }

Real64 TempIPtoSI(Real64 const Temp)
    {
        return (Temp - 32.0) * 5.0 / 9.0;
    }

Real64
    calculateOperationalFraction(Real64 const offTemperature, Real64 const controlTemperature, Real64 const throttlingRange)
    {
        Real64 temperatureDifference = std::abs(offTemperature - controlTemperature);
        if (temperatureDifference <= 0.0) {
            return 0.0; // No temperature difference--turn things off (set to zero); technically shouldn't happen
        }
        if (throttlingRange < 0.001) {
            return 1.0; // Throttling range is essentially zero and there is a temperature difference--turn it full on
        } // Temperature difference is non-zero and less than the throttling range--calculate the operation fraction, but limit to a maximum of 1.0
        return min(temperatureDifference / throttlingRange, 1.0);
    }

Real64 WaterConversionFunct(Real64 WaterTotal, Real64 ConversionFactor)
