Real64 Fahrenheit2Celsius(Real64 F)
{
    return (F - 32.0) * 5.0 / 9.0;
}

Real64 calcFluxWeightingFactor(const Real64 weightedHeatFlux, const Real64 uniformHeatFlux)
    {
        Real64 returnValue;
        Real64 constexpr tolerance = 1.0e-6;
        if (std::abs(uniformHeatFlux) <= tolerance) {
            returnValue = 1.0;
        } else {
            returnValue = weightedHeatFlux / uniformHeatFlux;
        }
        return returnValue;
    }

Real64 BoundValueToWithinTwoValues(Real64 const ValueToBound, Real64 const LowerBound, Real64 const UpperBound)
{

    // FUNCTION INFORMATION:
    //       AUTHOR         Edwin Lee
    //       DATE WRITTEN   September 2010
    //       MODIFIED       na
    //       RE-ENGINEERED  na

    // PURPOSE OF THIS FUNCTION:
    // Provides a clean way to quickly bound a generic value to within any two other values

    // METHODOLOGY EMPLOYED:
    // Bound up to min and down to max

    // Return value
    Real64 BoundedValue;

    BoundedValue = ValueToBound;
    BoundedValue = max(BoundedValue, LowerBound);
    BoundedValue = min(BoundedValue, UpperBound);

    return BoundedValue;
}

Real64 interpSetPoint(Real64 const LowVal, Real64 const HighVal, Real64 const RefVal, Real64 const SetptAtLowVal, Real64 const SetptAtHighVal)
{
    if (LowVal >= HighVal) {
        return 0.5 * (SetptAtLowVal + SetptAtHighVal);
    }
    if (RefVal <= LowVal) {
        return SetptAtLowVal;
    }
    if (RefVal >= HighVal) {
        return SetptAtHighVal;
    }
    return SetptAtLowVal - ((RefVal - LowVal) / (HighVal - LowVal)) * (SetptAtLowVal - SetptAtHighVal);
}

