Real64 LDSumMax(Real64 const Width, Real64 const Height)
    {
        // LDSumMax function calculates sum part of equation for maximum deflection
        // Width - glazing system width
        // Height - glazing system height

        // Using/Aliasing
        using namespace TARCOGParams;

        // Return value
        Real64 LDSumMax;

        // Locals
        int i;
        int j;

        LDSumMax = 0.0;
        for (i = 1; i <= TARCOGParams::MMax; i += 2) {
            Real64 const sin_i(std::sin(i * Constant::PiOvr2));
            Real64 const pow_i_W(pow_2(i / Width));
            for (j = 1; j <= TARCOGParams::NMax; j += 2) {
                LDSumMax += (sin_i * std::sin(j * Constant::PiOvr2)) / (i * j * pow_2(pow_i_W + pow_2(j / Height)));
            } // do j = 1, DeflectionParameters::NMax, 2
        } // do i = 1, DeflectionParameters::MMax, 2

        return LDSumMax;
    }

Real64 LDSumMean(Real64 const Width, Real64 const Height)
    {
        // LDSumMean function calculates sum part of equation for mean deflection
        // Width - glazing system width
        // Height - glazing system height

        // Using/Aliasing
        using namespace TARCOGParams;

        // Return value
        Real64 LDSumMean;

        // Locals
        Real64 constexpr Pi_squared(Constant::Pi * Constant::Pi);
        int i;
        int j;

        LDSumMean = 0.0;
        for (i = 1; i <= TARCOGParams::MMax; i += 2) {
            Real64 const pow_i_Pi_2(i * i * Pi_squared);
            Real64 const pow_i_W(pow_2(i / Width));
            for (j = 1; j <= TARCOGParams::NMax; j += 2) {
                LDSumMean += 4.0 / (pow_i_Pi_2 * pow_2(j) * pow_2(pow_i_W + pow_2(j / Height)));
            } // do j = 1, DeflectionParameters::NMax, 2
        } // do i = 1, MMax, 2

        return LDSumMean;
    }

Real64 pos(Real64 const x)
    {
        return (x + std::abs(x)) / 2.0;
    }

Real64 CalcFangerPPD(Real64 PMV)
    {
        Real64 PPD;
        Real64 expTest1 = -0.03353 * pow_4(PMV) - 0.2179 * pow_2(PMV);
        if (expTest1 > DataPrecisionGlobals::EXP_LowerLimit) {
            PPD = 100.0 - 95.0 * std::exp(expTest1);
        } else {
            PPD = 100.0;
        }

        if (PPD < 0.0) {
            PPD = 0.0;
        } else if (PPD > 100.0) {
            PPD = 100.0;
        }
        return PPD;
    }

Real64 CalcRelativeAirVelocity(Real64 AirVel, Real64 ActMet)
    {
        if (ActMet > 1) {
            return AirVel + 0.3 * (ActMet - 1);
        }
        return AirVel;
    }

Real64 CalcSatVapPressFromTemp(Real64 const Temp)
    {

        // FUNCTION INFORMATION:
        //     AUTHOR         Jaewook Lee
        //     DATE WRITTEN   January 2000
        //     MODIFIED       Rick Strand (for E+ implementation February 2000)

        // PURPOSE OF THIS FUNCTION:
        // THIS IS A FUNCTION TO CALCULATE THE SATURATED VAPOR PRESSURE
        // FROM AIR TEMPERATURE

        // METHODOLOGY EMPLOYED:
        // This function is based upon the work performed by Dan Maloney for
        // the BLAST program.
        // REFERENCES:
        // Maloney, Dan, M.S. Thesis, University of Illinois at Urbana-Champaign

        Real64 const XT(Temp / 100.0);
        return 6.16796 + 358.1855 * pow_2(XT) - 550.3543 * pow_3(XT) + 1048.8115 * pow_4(XT);

        // Helper function for pierceSET calculates Saturated Vapor Pressure (Torr) at Temperature T (°C)
        //        return Math.exp(18.6686 - 4030.183/(T + 235.0));
    }

Real64 CalcSatVapPressFromTempTorr(Real64 const Temp)
    {
        // Helper function for pierceSET calculates Saturated Vapor Pressure (Torr) at Temperature T (°C)
        return std::exp(18.6686 - 4030.183 / (Temp + 235.0));
    }

Real64 interpolateWindDirection(Real64 const prevHrWindDir, Real64 const curHrWindDir, Real64 const curHrWeight)
    {
        // adapted from http://stackoverflow.com/questions/2708476/rotation-interpolation
        Real64 curAng = curHrWindDir;
        Real64 prevAng = prevHrWindDir;
        Real64 diff = std::abs(curAng - prevAng);
        if (diff > 180.) {
            if (curAng > prevAng) {
                prevAng += 360.;
            } else {
                curAng += 360.;
            }
        }
        Real64 interpAng = prevAng + (curAng - prevAng) * curHrWeight;
        return (fmod(interpAng, 360.)); // fmod is float modulus function
    }

Real64 InterpolateBetweenTwoValues(Real64 const X, Real64 const X0, Real64 const X1, Real64 const F0, Real64 const F1)
    {

        // FUNCTION INFORMATION:
        //       AUTHOR         Brent Griffith
        //       DATE WRITTEN   June 2009
        //       MODIFIED       na
        //       RE-ENGINEERED  na

        // PURPOSE OF THIS FUNCTION:
        // Interpolate between two results

        // METHODOLOGY EMPLOYED:
        // linear interpolation

        Real64 InterpResult;

        InterpResult = F0 + ((X - X0) / (X1 - X0)) * (F1 - F0);
        return InterpResult;
    }

Real64 InterpolateBetweenFourValues(Real64 const X,
                                        Real64 const Y,
                                        Real64 const X1,
                                        Real64 const X2,
                                        Real64 const Y1,
                                        Real64 const Y2,
                                        Real64 const Fx1y1,
                                        Real64 const Fx1y2,
                                        Real64 const Fx2y1,
                                        Real64 const Fx2y2)
    {

        // FUNCTION INFORMATION:
        //       AUTHOR         Brent Griffith
        //       DATE WRITTEN   June 2009
        //       MODIFIED       na
        //       RE-ENGINEERED  na

        // PURPOSE OF THIS FUNCTION:
        // Interpolate between four results.

        // METHODOLOGY EMPLOYED:
        // bilinear interpolation (approximate)

        // REFERENCES:
        // http://en.wikipedia.org/wiki/Bilinear_interpolation

        // Return value
        Real64 InterpResult;

        InterpResult = (Fx1y1 / ((X2 - X1) * (Y2 - Y1))) * (X2 - X) * (Y2 - Y) + (Fx2y1 / ((X2 - X1) * (Y2 - Y1))) * (X - X1) * (Y2 - Y) +
                       (Fx1y2 / ((X2 - X1) * (Y2 - Y1))) * (X2 - X) * (Y - Y1) + (Fx2y2 / ((X2 - X1) * (Y2 - Y1))) * (X - X1) * (Y - Y1);
        return InterpResult;
    }
